import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { authApi } from "../services/api";

const Register = () => {
  const [form, setForm] = useState({ nom: "", prenom: "", email: "", password: "" });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const submit = async (e) => {
    e.preventDefault();
    try {
      await authApi.register(form);
      navigate("/login");
    } catch (err) {
      setError(err.response?.data?.detail || "Inscription échouée");
    }
  };

  return (
    <form className="max-w-md mx-auto bg-white p-6 rounded-xl shadow space-y-3" onSubmit={submit}>
      <h2 className="text-xl font-semibold">Inscription</h2>
      <input className="border p-2 rounded w-full" placeholder="Nom" value={form.nom} onChange={(e) => setForm({ ...form, nom: e.target.value })} />
      <input className="border p-2 rounded w-full" placeholder="Prénom" value={form.prenom} onChange={(e) => setForm({ ...form, prenom: e.target.value })} />
      <input className="border p-2 rounded w-full" placeholder="Email" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} />
      <input className="border p-2 rounded w-full" type="password" placeholder="Mot de passe" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} />
      {error && <p className="text-red-600 text-sm">{error}</p>}
      <button className="bg-primary text-white px-4 py-2 rounded">Créer un compte</button>
    </form>
  );
};

export default Register;
